// Business logic validation
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.schedulingData || item.json;
  const normalized = data.normalized;

  const errors = [];
  const warnings = [];

  // Validate date/time is in the future
  const now = new Date();
  const startTime = new Date(normalized.startTime);

  if (startTime <= now) {
    errors.push('Meeting time must be in the future');
  }

  // Validate working hours (9 AM - 5 PM by default)
  const workingHoursStart = parseInt(process.env.WORKING_HOURS_START?.split(':')[0] || '9');
  const workingHoursEnd = parseInt(process.env.WORKING_HOURS_END?.split(':')[0] || '17');
  const meetingHour = startTime.getHours();

  if (meetingHour < workingHoursStart || meetingHour >= workingHoursEnd) {
    warnings.push(`Meeting scheduled outside working hours (${workingHoursStart}:00 - ${workingHoursEnd}:00)`);
  }

  // Validate weekend
  const dayOfWeek = startTime.getDay();
  if (dayOfWeek === 0 || dayOfWeek === 6) {
    warnings.push('Meeting scheduled on weekend');
  }

  // Validate duration
  if (normalized.duration < 15) {
    errors.push('Meeting duration must be at least 15 minutes');
  }
  if (normalized.duration > 480) {
    errors.push('Meeting duration cannot exceed 8 hours');
  }

  // Validate attendees
  if (normalized.attendees.length === 0) {
    errors.push('At least one attendee is required');
  }
  if (normalized.attendees.length > 50) {
    warnings.push('Large number of attendees may impact scheduling');
  }

  // Validate meeting not too far in future (1 year max)
  const oneYearFromNow = new Date();
  oneYearFromNow.setFullYear(oneYearFromNow.getFullYear() + 1);
  if (startTime > oneYearFromNow) {
    warnings.push('Meeting scheduled more than 1 year in advance');
  }

  // Check lead time (at least 1 hour notice by default)
  const minLeadTimeMinutes = parseInt(process.env.MIN_LEAD_TIME_MINUTES || '60');
  const leadTimeMs = startTime - now;
  const leadTimeMinutes = leadTimeMs / (1000 * 60);

  if (leadTimeMinutes < minLeadTimeMinutes) {
    warnings.push(`Short notice: less than ${minLeadTimeMinutes} minutes lead time`);
  }

  const validated = {
    ...data,
    validation: {
      isValid: errors.length === 0,
      errors: errors,
      warnings: warnings,
      validatedAt: new Date().toISOString(),
      checks: {
        futureDate: startTime > now,
        workingHours: meetingHour >= workingHoursStart && meetingHour < workingHoursEnd,
        validDuration: normalized.duration >= 15 && normalized.duration <= 480,
        hasAttendees: normalized.attendees.length > 0,
        adequateLeadTime: leadTimeMinutes >= minLeadTimeMinutes
      }
    },
    stage: 'validated',
    processedAt: new Date().toISOString()
  };

  results.push({ json: validated });
}

return results;
